 text=build_live_markdown({"meta":{"version":"2.0","stage":"V2.0_live_manual_decision_system","latest_trade_date":"2026-06-18"},"live_manual_decision_quality":{"status":"WARN","failed_count":0,"warn_count":1},"live_decision_evidence_availability":{"all_required_available":True,"available_reports":[],"missing_reports":[],"failed_quality_gates":[],"warning_quality_gates":[]},"live_state_overview":{"overall_system_status":"ready_for_manual_review","status_reasons":[]},"path_observation_card":{},"risk_explanation_card":{"overall_risk_level":"high","primary_risk_sources":[],"secondary_risk_sources":[]},"evidence_conflict_card":{"evidence_conflict":True,"conflict_reasons":[]},"manual_review_checklist":[],"manual_confirmation_panel":{"decision_session_id":"session","decision_snapshot_id":"snapshot","manual_review_status":"not_started"},"manual_decision_status":"review_required","manual_review_required":True,"forbidden_actions":["formal_signal_generation","auto_order","broker_api"]})
 assert "CNSV V2.0" in text; assert "人工量化驾驶舱" in text; assert "建议买入" not in text; assert write_live_html(tmp_path/"live.html").exists()
